121	// ── Reliquary stamp witness ──────────────────────────────────
122	
123	/// Filename of a vessel's rbrv.env (relative to the vessel directory).
124	const RBTDRO_VESSEL_RBRV_FILE: &str = "rbrv.env";
125	
126	/// Field name yoked by case 1 in each vessel rbrv.env. Presence (non-empty)
127	/// is the cross-case witness that case 1 ran.
128	const RBTDRO_FIELD_RBRV_RELIQUARY: &str = "RBRV_RELIQUARY";
129	
130	/// Stable vessel chosen for the case-1 witness probe: sentry-tether is the
131	/// first entry in `RBTDRO_YOKE_VESSEL_DIRS` and is yoked on every conjure
132	/// path, so its rbrv.env always carries the stamp after case 1.
133	const RBTDRO_WITNESS_VESSEL_DIR: &str = RBTDRO_VESSEL_DIR_SENTRY_TETHER;
134	
135	// ── Graft override ───────────────────────────────────────────
136	
137	/// BURE_TWEAK signal recognized by rbfd_FoundryDirectorBuild for graft mode:
138	/// supplies the local image reference without mutating the vessel rbrv.env.
139	const RBTDRO_GRAFT_TWEAK_NAME: &str = "threemodegraft";
140	
141	/// Source image for graft: any locally-resolvable docker image works; an
142	/// upstream public image keeps this case independent of the conjure case.
143	const RBTDRO_GRAFT_SOURCE_IMAGE: &str = "busybox:latest";
144	
145	// ── Probes ───────────────────────────────────────────────────
146	//
147	// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
148	// have no context, so they read the project root from current_dir() — theurge
149	// always launches from the project root.
150	
151	fn rbtdro_probe_root() -> Result<PathBuf, String> {
152	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
153	}
154	
155	/// Read an env-file value or None if absent. Mirrors the helpers in rbtdrk
156	/// and rbtdrp — kept local to avoid cross-module coupling.
157	fn rbtdro_read_env_value(path: &Path, key: &str) -> Option<String> {
158	    let content = std::fs::read_to_string(path).ok()?;
159	    let prefix = format!("{}=", key);
160	    for line in content.lines() {
161	        let trimmed = line.trim_start();
162	        if trimmed.starts_with('#') {
163	            continue;
164	        }
165	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
166	            return Some(rest.to_string());
167	        }
168	    }
169	    None
170	}
171	
172	/// Cases 1, 2, 8, 9 probe: governor RBRA present at the canonical secrets path.
173	/// Established by canonical-establish §2 (rbtdrk_governor_mantle).
174	fn rbtdro_probe_governor_rbra() -> Result<(), String> {
175	    let root = rbtdro_probe_root()?;
176	    let path = rbtdrk_canonical_rbra(&root, "governor")?;
177	    if !path.exists() {
178	        return Err(format!("governor RBRA absent at {}", path.display()));
179	    }
180	    Ok(())
181	}
182	
183	/// Cases 3-7 probe: reliquary stamp yoked into the witness vessel's rbrv.env.
184	/// Case 1's yoke fan-out writes RBRV_RELIQUARY into every conjure-path vessel
185	/// and commits; reading the witness vessel's committed value is the cross-case
186	/// evidence that case 1 ran. No out-of-source-tree scratch state.
187	/// Kludge is local-only (no GCP), so governor RBRA is not a load-bearing
188	/// precondition for kludge; the witness presence confirms case 1 completed.
189	fn rbtdro_probe_reliquary_stamp() -> Result<(), String> {
190	    let root = rbtdro_probe_root()?;
191	    let rbrv = root
192	        .join(RBTDRO_WITNESS_VESSEL_DIR)
193	        .join(RBTDRO_VESSEL_RBRV_FILE);
194	    let value = rbtdro_read_env_value(&rbrv, RBTDRO_FIELD_RBRV_RELIQUARY).ok_or_else(|| {
195	        format!(
196	            "{} missing from {}",
197	            RBTDRO_FIELD_RBRV_RELIQUARY,
198	            rbrv.display()
199	        )
200	    })?;
201	    if value.trim().is_empty() {
202	        return Err(format!(
203	            "{} is empty in {}",
204	            RBTDRO_FIELD_RBRV_RELIQUARY,
205	            rbrv.display()
206	        ));
207	    }
208	    Ok(())
209	}
