211	// ── Helpers ──────────────────────────────────────────────────
212	
213	fn rbtdro_invoke_logged(
214	    ctx: &mut rbtdri_Context,
215	    colophon: &str,
216	    args: &[&str],
217	    extra_env: &[(&str, &str)],
218	    dir: &Path,
219	    label: &str,
220	) -> Result<rbtdri_InvokeResult, String> {
221	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
222	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
223	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
224	    Ok(result)
225	}
226	
227	/// Run an ordain on `vessel_dir` and return the captured hallmark string.
228	/// Writes invocation logs to `dir` under the `label` prefix; returns Fail
229	/// verdict-bearing Err so callers can early-return cleanly.
230	fn rbtdro_ordain_capture(
231	    ctx: &mut rbtdri_Context,
232	    dir: &Path,
233	    vessel_dir: &str,
234	    extra_env: &[(&str, &str)],
235	    label: &str,
236	) -> Result<String, rbtdre_Verdict> {
237	    let result = match rbtdro_invoke_logged(
238	        ctx,
239	        RBTDRM_COLOPHON_ORDAIN,
240	        &[vessel_dir],
241	        extra_env,
242	        dir,
243	        label,
244	    ) {
245	        Ok(r) => r,
246	        Err(e) => {
247	            return Err(rbtdre_Verdict::Fail(format!(
248	                "ordain {} invocation: {}",
249	                vessel_dir, e
250	            )))
251	        }
252	    };
253	    if result.exit_code != 0 {
254	        return Err(rbtdre_Verdict::Fail(format!(
255	            "ordain {} exit {}\n{}",
256	            vessel_dir, result.exit_code, result.stderr
257	        )));
258	    }
259	    let hallmark = match rbtdri_read_burv_fact(&result, RBTDRC_FACT_HALLMARK) {
260	        Ok(s) => s,
261	        Err(e) => {
262	            return Err(rbtdre_Verdict::Fail(format!(
263	                "read hallmark fact after ordain {}: {}",
264	                vessel_dir, e
265	            )))
266	        }
267	    };
268	    let _ = std::fs::write(dir.join(format!("{}-hallmark.txt", label)), &hallmark);
269	    Ok(hallmark)
270	}
271	
272	/// Yoke the reliquary stamp into a vessel's rbrv.env. The yoke tabtarget
273	/// validates the stamp and writes RBRV_RELIQUARY; the handbook ceremony
274	/// includes a commit step the operator performs by hand, which the fixture
275	/// skips since the yoke value is rerun-derivable from the scratch file.
276	fn rbtdro_yoke(
277	    ctx: &mut rbtdri_Context,
278	    dir: &Path,
279	    stamp: &str,
280	    vessel_sigil: &str,
281	    label: &str,
282	) -> Result<(), rbtdre_Verdict> {
283	    let result = match rbtdro_invoke_logged(
284	        ctx,
285	        RBTDRM_COLOPHON_YOKE_RELIQUARY,
286	        &[vessel_sigil, stamp],
287	        &[],
288	        dir,
289	        label,
290	    ) {
291	        Ok(r) => r,
292	        Err(e) => {
293	            return Err(rbtdre_Verdict::Fail(format!(
294	                "yoke {} invocation: {}",
295	                vessel_sigil, e
296	            )))
297	        }
298	    };
299	    if result.exit_code != 0 {
300	        return Err(rbtdre_Verdict::Fail(format!(
301	            "yoke {} exit {}\n{}",
302	            vessel_sigil, result.exit_code, result.stderr
303	        )));
304	    }
305	    Ok(())
306	}
