308	/// Enshrine one vessel — mirrors that vessel's RBRV_IMAGE_n_ORIGIN bases
309	/// to GAR and writes back the resulting RBRV_IMAGE_n_ANCHOR digests.
310	/// `rbfd_enshrine` is per-vessel; the airgap chain calls this twice with
311	/// different vessels (forge first, then airgap-bottle).
312	fn rbtdro_enshrine(
313	    ctx: &mut rbtdri_Context,
314	    dir: &Path,
315	    vessel_sigil: &str,
316	    label: &str,
317	) -> Result<(), rbtdre_Verdict> {
318	    let result = match rbtdro_invoke_logged(
319	        ctx,
320	        RBTDRM_COLOPHON_ENSHRINE_VESSEL,
321	        &[vessel_sigil],
322	        &[],
323	        dir,
324	        label,
325	    ) {
326	        Ok(r) => r,
327	        Err(e) => return Err(rbtdre_Verdict::Fail(format!("enshrine invocation: {}", e))),
328	    };
329	    if result.exit_code != 0 {
330	        return Err(rbtdre_Verdict::Fail(format!(
331	            "enshrine {} exit {}\n{}",
