338	/// Pull a docker image. Used by the graft case to ensure the source image
339	/// is locally resolvable before the BURE_TWEAK-overridden ordain.
340	fn rbtdro_docker_pull(image_ref: &str) -> Result<(), String> {
341	    let output = std::process::Command::new("docker")
342	        .args(["pull", image_ref])
343	        .output()
344	        .map_err(|e| format!("docker pull exec failed: {}", e))?;
345	    if !output.status.success() {
346	        return Err(format!(
347	            "docker pull {} exited {}: {}",
348	            image_ref,
349	            output.status.code().unwrap_or(-1),
350	            String::from_utf8_lossy(&output.stderr).trim()
351	        ));
352	    }
353	    Ok(())
354	}
355	
356	/// Drive a hallmark value into a nameplate's rbrn.env. Mirrors the
357	/// zrbob_drive_hallmark substitution logic from rbob_bottle.sh: load file
358	/// lines, replace the matching `VAR=*` line with the new value, atomic rename.
359	/// Returns Err if the variable line is not found (hard fail — configuration error).
360	fn rbtdro_drive_hallmark(
361	    root: &Path,
362	    nameplate: &str,
363	    var_name: &str,
364	    hallmark: &str,
365	) -> Result<(), String> {
366	    let rbrn_path = root.join(".rbk").join(nameplate).join("rbrn.env");
367	    let file = std::fs::File::open(&rbrn_path)
368	        .map_err(|e| format!("open rbrn.env for {}: {}", nameplate, e))?;
369	
370	    let lines: Vec<String> = BufReader::new(file)
371	        .lines()
372	        .collect::<Result<_, _>>()
373	        .map_err(|e| format!("read rbrn.env for {}: {}", nameplate, e))?;
374	
375	    let prefix = format!("{}=", var_name);
376	    let mut found = false;
377	    let rewritten: Vec<String> = lines
378	        .into_iter()
379	        .map(|line| {
380	            if line.starts_with(&prefix) {
381	                found = true;
382	                format!("{}={}", var_name, hallmark)
383	            } else {
384	                line
385	            }
386	        })
387	        .collect();
388	
389	    if !found {
390	        return Err(format!(
391	            "variable {} not found in .rbk/{}/rbrn.env",
392	            var_name, nameplate
393	        ));
394	    }
395	
396	    let tmp_path = root
397	        .join(".rbk")
398	        .join(nameplate)
399	        .join("rbrn.env.drive_tmp");
400	    {
401	        let mut tmp = std::fs::File::create(&tmp_path)
402	            .map_err(|e| format!("create tmp rbrn.env for {}: {}", nameplate, e))?;
403	        for line in &rewritten {
404	            writeln!(tmp, "{}", line)
405	                .map_err(|e| format!("write tmp rbrn.env for {}: {}", nameplate, e))?;
406	        }
407	    }
408	    std::fs::rename(&tmp_path, &rbrn_path)
409	        .map_err(|e| format!("atomic replace rbrn.env for {}: {}", nameplate, e))?;
410	    Ok(())
411	}
412	
413	/// Auto-commit helper. Checks git status --porcelain; if the working tree is
414	/// clean, returns Ok without committing. Otherwise runs `git add -A` then
415	/// `git commit -m <message>`. Theurge launches from project root so no
416	/// explicit current_dir is needed.
417	fn rbtdro_git_commit(message: &str) -> Result<(), rbtdre_Verdict> {
418	    let status = std::process::Command::new("git")
419	        .args(["status", "--porcelain"])
420	        .output()
421	        .map_err(|e| {
422	            rbtdre_Verdict::Fail(format!("git status --porcelain exec failed: {}", e))
423	        })?;
424	    if !status.status.success() {
425	        return Err(rbtdre_Verdict::Fail(format!(
426	            "git status --porcelain exited {}",
427	            status.status.code().unwrap_or(-1)
428	        )));
429	    }
430	    let porcelain = String::from_utf8_lossy(&status.stdout);
431	    if porcelain.trim().is_empty() {
432	        // Nothing to commit — clean tree is not an error.
433	        return Ok(());
434	    }
435	
436	    let add = std::process::Command::new("git")
437	        .args(["add", "-A"])
438	        .output()
439	        .map_err(|e| rbtdre_Verdict::Fail(format!("git add -A exec failed: {}", e)))?;
440	    if !add.status.success() {
441	        return Err(rbtdre_Verdict::Fail(format!(
442	            "git add -A exited {}: {}",
443	            add.status.code().unwrap_or(-1),
444	            String::from_utf8_lossy(&add.stderr).trim()
445	        )));
446	    }
447	
448	    let commit = std::process::Command::new("git")
449	        .args(["commit", "-m", message])
450	        .output()
451	        .map_err(|e| rbtdre_Verdict::Fail(format!("git commit exec failed: {}", e)))?;
452	    if !commit.status.success() {
453	        return Err(rbtdre_Verdict::Fail(format!(
454	            "git commit exited {}: {}",
455	            commit.status.code().unwrap_or(-1),
456	            String::from_utf8_lossy(&commit.stderr).trim()
457	        )));
458	    }
459	    Ok(())
460	}
461	
462	/// Kludge helper: build sentry and bottle locally for a nameplate. Both steps
463	/// are local docker builds with no GCP dependency. The kludge tabtargets drive
464	/// hallmarks directly into the nameplate's rbrn.env via zrbob_drive_hallmark.
465	/// rbw-cKS and rbw-cKB are global (param1-channel) tabtargets — no imprint suffix,
466	/// nameplate passed as a positional argument.
467	fn rbtdro_kludge_nameplate(
468	    ctx: &mut rbtdri_Context,
469	    dir: &Path,
470	    nameplate: &str,
471	) -> Result<(), rbtdre_Verdict> {
472	    let sentry_result = match rbtdro_invoke_logged(
473	        ctx,
474	        RBTDRM_COLOPHON_KLUDGE_SENTRY,
475	        &[nameplate],
476	        &[],
477	        dir,
478	        &format!("kludge-sentry-{}", nameplate),
479	    ) {
480	        Ok(r) => r,
481	        Err(e) => {
482	            return Err(rbtdre_Verdict::Fail(format!(
483	                "kludge sentry {} invocation: {}",
484	                nameplate, e
485	            )))
486	        }
487	    };
488	    if sentry_result.exit_code != 0 {
489	        return Err(rbtdre_Verdict::Fail(format!(
490	            "kludge sentry {} exit {}\n{}",
491	            nameplate, sentry_result.exit_code, sentry_result.stderr
492	        )));
493	    }
494	
495	    // Commit sentry hallmark before bottle kludge — kludge asserts clean tree.
496	    rbtdro_git_commit(&format!("BBAAu kludge-{}: sentry hallmark", nameplate))?;
497	
498	    let bottle_result = match rbtdro_invoke_logged(
499	        ctx,
500	        RBTDRM_COLOPHON_KLUDGE_BOTTLE,
501	        &[nameplate],
502	        &[],
503	        dir,
504	        &format!("kludge-bottle-{}", nameplate),
505	    ) {
506	        Ok(r) => r,
507	        Err(e) => {
508	            return Err(rbtdre_Verdict::Fail(format!(
509	                "kludge bottle {} invocation: {}",
510	                nameplate, e
511	            )))
512	        }
513	    };
514	    if bottle_result.exit_code != 0 {
515	        return Err(rbtdre_Verdict::Fail(format!(
516	            "kludge bottle {} exit {}\n{}",
517	            nameplate, bottle_result.exit_code, bottle_result.stderr
518	        )));
519	    }
520	
521	    rbtdro_git_commit(&format!("BBAAu kludge-{}: bottle hallmark", nameplate))?;
522	    Ok(())
523	}
