525	/// Inscribe the depot-wide reliquary toolchain. Captures the reliquary
526	/// stamp from BURV fact, persists it to the fixture scratch file, then
527	/// yokes the stamp into all ordain-side vessels in one pass and auto-commits.
528	fn rbtdro_onboarding_inscribe_reliquary(dir: &Path) -> rbtdre_Verdict {
529	    let probe = rbtdrb_Probe {
530	        name: "governor RBRA present",
531	        check: rbtdro_probe_governor_rbra,
532	        remediation: "rerun canonical-establish (rbtdrk_governor_mantle) before this fixture",
533	    };
534	    if let Err(v) = rbtdrb_assert(&probe) {
535	        return v;
536	    }
537	    rbtdrc_with_ctx(|ctx| rbtdro_onboarding_inscribe_reliquary_impl(ctx, dir))
538	}
539	
540	fn rbtdro_onboarding_inscribe_reliquary_impl(
541	    ctx: &mut rbtdri_Context,
542	    dir: &Path,
543	) -> rbtdre_Verdict {
544	    let result = match rbtdro_invoke_logged(
545	        ctx,
546	        RBTDRM_COLOPHON_INSCRIBE_RELIQUARY,
547	        &[],
548	        &[],
549	        dir,
550	        "inscribe",
551	    ) {
552	        Ok(r) => r,
553	        Err(e) => return rbtdre_Verdict::Fail(format!("inscribe invocation: {}", e)),
554	    };
555	    if result.exit_code != 0 {
556	        return rbtdre_Verdict::Fail(format!(
557	            "inscribe exit {}\n{}",
558	            result.exit_code, result.stderr
559	        ));
560	    }
561	
562	    let stamp = match rbtdri_read_burv_fact(&result, RBTDRC_FACT_RELIQUARY) {
563	        Ok(s) => s,
564	        Err(e) => return rbtdre_Verdict::Fail(format!("read reliquary fact: {}", e)),
565	    };
566	    let _ = std::fs::write(dir.join("reliquary-stamp.txt"), &stamp);
567	
568	    // Yoke stamp into all ordain-side vessels in one pass.
569	    for vessel_dir in RBTDRO_YOKE_VESSEL_DIRS {
570	        let sigil = vessel_dir.rsplit('/').next().unwrap_or(vessel_dir);
571	        let label = format!("yoke-{}", sigil);
572	        if let Err(v) = rbtdro_yoke(ctx, dir, &stamp, sigil, &label) {
573	            return v;
574	        }
575	    }
576	
577	    // Commit the rbrv.env changes for all yoked vessels.
578	    if let Err(v) = rbtdro_git_commit(
579	        "BBAAu inscribe-reliquary: yoke stamp into all ordain-side vessels",
580	    ) {
581	        return v;
582	    }
583	
584	    rbtdre_Verdict::Pass
585	}
